#!/bin/bash
# Validate generated files are up-to-date
# Checks service-worker, API client, and other generated files
# Note: This check runs BEFORE auto-regeneration, so false positives are expected
# Auto-regeneration happens in parallel hooks that fix these issues

source "$(dirname "$0")/../shared/common-functions.sh"

log_info "Validating generated files..."

ERRORS=0
WARNINGS=0

# Check service-worker.js
# Only warn if source changed AND service-worker hasn't been regenerated
# Note: auto-regenerate-service-worker hook will fix this automatically
if [ -f "apps/web/public/service-worker.js" ]; then
  SW_TIME=$(stat -f "%m" apps/web/public/service-worker.js 2>/dev/null || stat -c "%Y" apps/web/public/service-worker.js 2>/dev/null)
  
  # Check if service worker source files were modified in this commit
  CHANGED_SW_SOURCES=$(git diff --cached --name-only | grep -E "(minify-service-worker|generate-service-worker|category-config)" || echo "")
  
  if [ -n "$CHANGED_SW_SOURCES" ]; then
    # Source changed, check if service-worker is newer or equal
    # If service-worker is older, auto-regeneration will fix it
    SW_SOURCE_TIME=$(stat -f "%m" packages/generators/src/bin/minify-service-worker.ts 2>/dev/null || stat -c "%Y" packages/generators/src/bin/minify-service-worker.ts 2>/dev/null)
    
    if [ -n "$SW_TIME" ] && [ -n "$SW_SOURCE_TIME" ] && [ "$SW_SOURCE_TIME" -gt "$SW_TIME" ]; then
      # Source is newer - auto-regeneration will handle this
      # Just log info, don't error (non-blocking)
      log_info "service-worker.js will be auto-regenerated by auto-regenerate-service-worker hook"
      WARNINGS=$((WARNINGS + 1))
    fi
  fi
fi

# Check API client
# Only warn if openapi.json changed AND API client hasn't been regenerated
# Note: auto-regenerate-openapi hook will fix this automatically
if [ -f "packages/database-types/src/api-client/client.generated.ts" ]; then
  API_TIME=$(stat -f "%m" packages/database-types/src/api-client/client.generated.ts 2>/dev/null || stat -c "%Y" packages/database-types/src/api-client/client.generated.ts 2>/dev/null)
  
  # Check if OpenAPI spec or API routes were modified in this commit
  CHANGED_API=$(git diff --cached --name-only | grep -E "(openapi\.json|apps/web/src/app/api.*route\.ts$)" || echo "")
  
  if [ -n "$CHANGED_API" ]; then
    # OpenAPI or routes changed, check if API client is newer or equal
    OPENAPI_TIME=$(stat -f "%m" openapi.json 2>/dev/null || stat -c "%Y" openapi.json 2>/dev/null)
    
    if [ -n "$API_TIME" ] && [ -n "$OPENAPI_TIME" ] && [ "$OPENAPI_TIME" -gt "$API_TIME" ]; then
      # OpenAPI is newer - auto-regeneration will handle this
      # Just log info, don't error (non-blocking)
      log_info "API client will be auto-regenerated by auto-regenerate-openapi hook"
      WARNINGS=$((WARNINGS + 1))
    fi
  fi
fi

# Only fail if there are actual errors (files missing), not warnings (auto-regeneration will fix)
# Exit with success (non-blocking - auto-regeneration hooks will fix)
# Warnings are informational only, not errors
if [ $ERRORS -gt 0 ]; then
  exit 1
fi

if [ $WARNINGS -eq 0 ]; then
  log_success "All generated files are up-to-date"
else
  # Files will be auto-regenerated, just log info
  log_info "Generated files will be auto-regenerated if needed"
fi
exit 0
